declare @name nvarchar(4000)
select @name = case @reportBy
  when '1' then case when @@language = 'V' then N'Mã vật tư' else 'Item Code' end
  when '2' then case when @@language = 'V' then N'Nhóm vật tư 1' else 'Item Group 1' end
  when '3' then case when @@language = 'V' then N'Nhóm vật tư 2' else 'Item Group 2' end
  when '4' then case when @@language = 'V' then N'Nhóm vật tư 3' else 'Item Group 3' end
  when '5' then case when @@language = 'V' then N'Nhóm giá vật tư' else 'Item Price Class' end
  when '6' then case when @@language = 'V' then N'Mã khách hàng' else 'Customer' end
  when '7' then case when @@language = 'V' then N'Nhóm khách hàng 1' else 'Customer Group 1' end
  when '8' then case when @@language = 'V' then N'Nhóm khách hàng 2' else 'Customer Group 2' end
  when '9' then case when @@language = 'V' then N'Nhóm khách hàng 3' else 'Customer Group 3' end
  when '10' then case when @@language = 'V' then N'Nhóm giá khách hàng' else 'Customer Price Class' end
  when '11' then case when @@language = 'V' then N'Nhân viên bán hàng' else 'Sales Employee' end
  when '12' then case when @@language = 'V' then N'Mã đơn vị cơ sở' else 'Unit' end
  when '13' then case when @@language = 'V' then N'Mã kho' else 'Site' end
  when '14' then case when @@language = 'V' then N'Mã bộ phận' else 'Department' end
end
select 'this._itemName = ''' + isnull(rtrim(replace(replace(@name, '\', '\\'), '''', '\''')), '') + ''';this._queryFilterString = ''' + replace(replace(@@queryString, '\', '\\'), '''', '\''') + ''';init$GridQuery$(this);' as message
return




