      &DeclareCommandFilter;



        &QueryString;

declare @queryWhereClause nvarchar(4000), @queryFormClause nvarchar(4000), @bc_theo varchar(48), @nh_theo varchar(48)

select @bc_theo = case @reportBy
  when '1' then 'a.ma_vt' when '2' then 'b.nh_vt1' when '3' then 'b.nh_vt2' when '4' then 'b.nh_vt3'
  when '5' then 'b.nh_vt9' when '6' then 'a.ma_kh' when '7' then 'c.nh_kh1' when '8' then 'c.nh_kh2' when '9' then 'c.nh_kh3'
  when '10' then 'c.nh_kh9' when '11' then 'a.ma_nvbh' when '12' then 'a.ma_dvcs' when '13' then 'a.ma_kho' when '14' then 'a.ma_bp'
end
select @nh_theo = case @groupBy
  when '0' then '' when '1' then 'a.ma_vt' when '2' then 'b.nh_vt1' when '3' then 'b.nh_vt2' when '4' then 'b.nh_vt3'
  when '5' then 'b.nh_vt9' when '6' then 'a.ma_kh' when '7' then 'c.nh_kh1' when '8' then 'c.nh_kh2' when '9' then 'c.nh_kh3'
  when '10' then 'c.nh_kh9' when '11' then 'a.ma_nvbh' when '12' then 'a.ma_dvcs' when '13' then 'a.ma_kho' when '14' then 'a.ma_bp'
end

select @queryFormClause = 'left join dmvt b on a.ma_vt = b.ma_vt left join dmkh c on a.ma_kh = c.ma_kh '
select @queryWhereClause = ''+ @bc_theo + ' = ''' +  replace(@xDetail, '''', '''''') + ''' and a.status = ''1'''
if @nh_theo <> '' select @queryWhereClause = @queryWhereClause + ' and ' + @nh_theo + ' = ''' +  replace(@tKey, '''', '''''') + ''''
if @voucherList <> '' select @queryWhereClause = @queryWhereClause + ' and ma_ct in (''' + replace(replace(replace(@voucherList, ' ', ''), '''', ''''''), ',', ''',''') + ''')'
if @revenueAcc <> '' select @queryWhereClause = @queryWhereClause + ' and a.tk_dt like ''' +  replace(@revenueAcc, '''', '''''') + '%'''
&FilterInitialize;&FilterQuery;
exec FastBusiness$Report$StockDetail @@refresh, @@pageIndex, @@pageCount, @@lastPage, @@lastCount, @@firstItem, @@lastItem,
  @@textExternal, @queryFormClause, @queryWhereClause, @dFrom, @dTo, @unit, @dataType, @@admin, @@userID, 'rptMultiPeriodSalesAnalysisByTwoCriteria', '@@sysDatabaseName', default, @@aggregation







      &JavascriptReportInit;
      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253)), v = g._language == 'v';
  var _report = (v ? 'Báo cáo theo: ' : 'Report by:'), _period = (v ? 'số kỳ báo cáo: ' : 'No. of Periods:');
  switch (a[3]) {
    case '1':
      _report = _report + " " + (v ? 'Tháng' : 'Month');
      break;
    case '2':
      _report = _report + " " + (v ? 'Quý' : 'Quarter');
      break;
    case '3':
      _report = _report + " " + (v ? 'Nửa năm' : 'Half a Year');
      break;
    case '4':
      _report = _report + " " + (v ? 'Năm' : 'Year');
      break;
    default:
      break;
  }
  g._alterTitle = [null, [['%c', a[0], true], ['%s', g._itemName, true], ['%t', _report, true], ['%d2', _period + " " + a[4], true], ['%d1', formatDateView(a[2]), true]]];
  var x = a[9], y = a[7];
  if (y == '1'){
    g._hiddenFields = [
      {Fields: 'tien_nt2, ma_nt', Value: (x == '10'},
      {Fields: 'tien2', Value: (x == '20')},
      {Fields: 'ck_nt, ck', Value: (x == '10' || x == '20')}];
  } else if (y == '2'){
    g._hiddenFields = [
      {Fields: 'ck_nt, ma_nt', Value: (x == '10'},
      {Fields: 'ck', Value: (x == '20')},
      {Fields: 'tien_nt2, tien2', Value: (x == '10' || x == '20')}];
  }
}
